function SimpleForm() {
  const [value, setValue] = useState("");

  // Функція-обробник події відправки
  const handleSubmit = (e) => {
    e.preventDefault(); // КРИТИЧНО: зупиняємо перезавантаження сторінки
    console.log("Відправлено дані:", value);
    setValue(""); // Очищуємо поле
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="text"
        value={value}
        onChange={(e) => setValue(e.target.value)}
        placeholder="Введіть команду..."
      />
      <button type="submit">Виконати</button>
    </form>
  );
}
